import{_ as t,o as i,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const l="/images/uebung035.jpg",d="/images/uebung036.jpg",g=JSON.parse('{"title":"Übung Lektion 23","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung23.md","filePath":"lektionen/uebung23.md"}'),s={name:"lektionen/uebung23.md"};function o(a,e,u,h,b,p){return i(),n("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-23" tabindex="-1">Übung Lektion 23 <a class="header-anchor" href="#ubung-lektion-23" aria-label="Permalink to &quot;Übung Lektion 23&quot;">​</a></h1><p>A) Folgende Wurzeln bilden den Infinitiv ohne Bindevokal -i-. Bilden Sie den Infinitiv unter Beachtung der Lautveränderungen zu:</p><ol><li>आप् आप्तुम्</li><li>इ एतुम्</li><li>गम् गन्तुम्</li><li>कृ कर्तुम्</li><li>क्रुध् क्रोद्धुम्</li><li>जि जेतुम्</li><li>दुह् दोग्धुम्</li><li>दिश् देष्टुम्</li><li>दह् दग्धुम्</li><li>सृज् स्रष्टुम्</li><li>द्विष् द्वेष्टुम्</li><li>नी नेतुम्</li><li>पद् पत्तुम्</li><li>पा १ पातुम्</li><li>पा २ पातुम्</li><li>भज् भक्तुम्</li><li>कृष् कर्ष्टुम् । क्रष्टुम्</li><li>सु सोतुम्</li><li>मन् मन्तुम्</li><li>मुच् मोक्तुम्</li><li>मृ मर्तुम्</li><li>यज् यष्टुम्</li><li>युध् योद्धुम्</li><li>वच् वक्तुम्</li><li>विश् वेष्टुम्</li><li>श्रु श्रोतुम्</li><li>प्रच्छ् प्रष्टुम्</li><li>सिच् सेक्तुम्</li><li>स्तु स्तोतुम्</li><li>स्था स्थातुम्</li><li>स्मृ स्मर्तुम्</li><li>हन् हन्तुम्</li><li>लभ् लब्धुम्</li><li>अद् अत्तुम्</li><li>दृश् द्रष्टुम्</li><li>पच् पक्तुम्</li><li>सद् सत्तुम्</li></ol><p>B) Folgende Wurzeln bilden den Infinitiv mit Bindevokal -i-. Bilden Sie den Infinitiv zu:</p><ol><li>आस् आसितुम्</li><li>नृत् नर्तितुम्</li><li>रक्ष् रक्षितुम्</li><li>रुद् रोदितुम्</li><li>वद् वदितुम्</li><li>वृत् वर्तितुम्</li><li>कुप् कोपितुम्</li></ol><p>C) Folgende Wurzeln wahlweise mit oder ohne Bindevokal:</p><ol><li>अश् अशितुम् । अष्टुम्</li><li>इष् एष्टुम् । एषितुम्</li><li>बुध् बोधितुम् । बोद्धुम्</li><li>मुह् (3 Formen!) मोहितुम् । मग्धुम् । मोढुम्</li><li>सह् सहितुम् । सोढुम्</li></ol><p>D) Übersetzen Sie und lösen Sie die Komposita auf:</p><p>नराः स्वर्गं लब्धुं देवान्यज्ञ्नैर्यष्टुमिच्छन्ति ॥१॥ Um einen Himmel zu erlangen, wünschen Menschen, Götter mit Opfern zu verehren-</p><p>महापुण्यं कृत्वा गतपापजनेन नरकं गन्तुं न शक्यते ॥२॥ महत्पुण्यम् । गतं पापं यस्य तेन जनेन । Wenn jemand viel Verdienstliches getan hat, kann eine Mensch, der frei von bösem ist, nicht in eine Hölle kommen.</p><p>फलवन्ति पुण्यानीति सज्जनो ऽधर्मं कर्तुं नेच्छति ॥३॥ सञ्जनः । न धर्मम् । Da verdienstvolle Taten fruchtbar sind, will eine guter Mensch kein Unrecht tun.</p><p>सुगतो लोकान्मोक्तुमार्यसत्यान्युपदिशति ॥४॥ Um die Welten zu erlösen, lehrt Buddha die edlen Wahrheiten.</p><p>शूद्रजनो ब्राह्मणेन सहात्तुं नार्हति ॥५॥ शुद्राणां जनः । Śūdras dürfen mit einem Brahmanen zusammen nicht essen.</p><p>लोभसम्पन्ननरा नृत्यन्तीं सम्पन्नरूपदासीं द्रष्टुं गताः ॥६॥  लोभेन सम्पन्ना नराः । सम्पन्नं रूपं यस्यास्ताम् । Voll Gier sind die Männer gegangen, um die wunderschöne Dienerin tanzen zu sehen.</p><p>शूद्रया संगत्य ब्राह्मणो यष्टुं नार्हति ॥७॥ Wenn ein Brahmane mit einer Śūdra Geschlechtsverkehr hatte, darf er nicht opfern.</p><p>धर्मं श्रोतुकामा ब्राह्मणी सपुत्रा गुरुं द्रष्टुं महानगरं गता ॥८॥ श्रोतुं कामो यस्याः सा । पुत्रेण सह । महन्नगरम् । Weil sie über den Dharma hören wollte, ist die Brahmanin mit ihrem Sohn in die Großstadt gegangen, um den Meister zu treffen.</p><p>C) Übersetzen Sie folgendes सुभाषितम्</p><p>आहारनिद्राभयमैथुनं च<br> सामान्यमेतत्पशुभिर्नराणाम् ।<br> धर्मे हि तेषा्मधिको विशेषो<br> धर्मेण हीनाः पशुभिः समानाः ॥</p><p>Essen, Schlafen, Furcht und Sex ist den Menschen mit dem Vieh gemein. Der hervorhebende Unterschied der Menschen liegt im Dharma. Ohne Dharma sind sie dem Vieh gleich.</p><p><img src="'+l+'" alt=""><br> Abb.:  आहारनिद्राभयमैथुनं च<br> सामान्यमेतत्पशुभिर्नराणाम् ।<br> जैसलमेर<br> [Bildquelle: Peter Davis. -- <a href="http://www.flickr.com/photos/pediddle/327742179/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/pediddle/327742179/</a>. -- Zugriff am 2008-12-23. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Bitte keine Hilfsmittel benutzen!</p><p>A) Übersetzen Sie ins Sanskrit:</p><p>1. Die fünf (पञ्च) &quot;Qualen&quot; sind: Unwissenheit, der falsche Glaube ans Ich, Zuneigung, Abneigung und Anhänglichkeit an den Leib.</p><blockquote><p>अविद्यास्मितारागद्वेषाभिनिवेशाः पञ्च क्लेशाः ।</p></blockquote><p>2. Wissen gibt es für Gehorsam gegenüber einem Lehrer oder für viel Geld oder im Austausch gegen Wissen. Eine vierte Art von Wissenserwerb gibt es nicht.</p><blockquote><p>गुरुशुश्रूषया विद्या<br> पुष्कलेन धनेन वा ।<br> अथवा विद्यया विद्या<br> चतुर्थी नैव विद्यते ॥</p></blockquote><p>3. Ein Niedriger spricht, handelt aber nicht ; ein Guter spricht nicht, sondern handelt nur.</p><blockquote><p>निचो वदति न कुरुते<br> वदति न साधुः करोत्येव ॥</p></blockquote><p>4. Die Hilfswissenschaften zum Veda sind: Aussprachelehre, Ritualistik, Grammatik, Bedeutungslehre, Metrik (छन्दस्) und Kalenderlehre.</p><blockquote><p>शिक्षा कल्पो व्याकरणं निरुक्तं छन्दो ज्योतिषमङ्गानि |</p></blockquote><p>5. Yoga ist das Stoppen der Tätigkeiten des Denkorgans.</p><blockquote><p>योगश्चित्तवृत्तिनिरोधः ॥</p></blockquote><p>6. Recht siegt, nicht Unrecht ; Wahrheit siegt, nicht Lüge ; Geduld siegt, nicht Zorn ; Gott siegt, nicht ein Gegengott. (Passiv)</p><blockquote><p>धर्मो जयति नधर्मः<br> सत्यं जयति नानृतम् |<br> क्षमा जयति न क्रोधो<br> देवो जयति नासुरः ||</p></blockquote><p>7. Der &quot;Stock&quot; bewirkt Erwerb und sicheren Besitz von Philosophie, Veda und Ökonomie. Die Führung dieses Stocks ist Politik.</p><blockquote><p>आन्वीक्षिकीत्रयीवार्त्तानां योगक्षेमसाधनो दण्डः, तस्य नीतिर्दण्डनीतिः ॥</p></blockquote><p>8. Gattin, Sohn und Sklave, diese drei (त्रयस्) sind gemäß der Überlieferung besitzlos. Wozu diese kommen, das gehört dem, dem diese (drei) gehören.</p><blockquote><p>भार्या पुत्रश्च दासश्च<br> त्रय एवाधनाः स्मृताः ।<br> यत्ते समधिगच्छन्ति<br> यस्य ते तस्य तद्धनम् ॥</p></blockquote><p>9. Mücken wünschen eine Wunde, Herrscher wünschen Besitz, Niedrige wünschen Streit, Gute wünschen Frieden.</p><blockquote><p>मक्षिका व्रणमिच्छन्ति<br> धनमिच्छन्ति पार्थिवाः |<br> नीचाः कलहमिच्छन्ति<br> शान्तिमिच्छन्ति साधवः ||</p></blockquote><p>10. Die spezifische Pflicht eines Brahmanen ist: Studium, Lehren, Opfern als Opferherr, Opfern im Auftrag, Geben und Empfangen ; die eines Kṣatriya ist: Studium, Opfern als Opferherr, Geben, Lebensunterhalt durch Waffen, Hüten der Wesen ; die eines Vaiśya: Studium, Opfern als Opferherr, Geben, Ackerbau, Viehhaltung und Handel ; die eines Śūdra: Gehorsam gegenüber den Zweimalgeborenen, Wirtschaftstätigkeit, Tätigkeit (कर्म) von Handwerkern und Schaustellern.</p><blockquote><p>स्वधर्मो ब्राह्मणस्याध्ययनमध्यापनं यजनं याजनं दानं प्रतिग्रहश्च । क्षत्रियस्याध्ययनं यजनं दानं शस्त्राजीवो भूतरक्षणं च । वैश्यस्याध्ययनं यजनं दानं कृषिपाशुपाल्ये वणिज्या च । शूद्रस्य द्विजातिशुश्रूषा वार्त्ता कारुकुशीलवकर्म च ॥</p></blockquote><p>11. Abklärung des Bewusstseins geschieht aufgrund der meditativen Entfaltung von freundlichem Wohlwollen, Mitgefühl, Mitfreude und Gleichmut, die als Objekt Glück und Leid, Gutes und Böses haben.</p><blockquote><p>मैत्रीकरुणामुदितोपेक्षाणां सुखदुःखपुण्यापुण्यविषयाणां भावनतश्चित्तप्रसादनम् ॥</p></blockquote><p>12. Arme haben viele Söhne, obwohl sie sie nicht wünschen. Reiche haben keinen Sohn. Seltsam ist die Regung des Schicksals.</p><blockquote><p>सन्ति पुत्राः सुबहवो<br> दरिद्राणामनिच्छताम् ।<br> नास्ति पुत्रः समृद्धानां<br> विचित्रं विधिचेष्टितम् ॥</p></blockquote><p>14. Wen erschlägt nicht ein Frauenkörper (वपुस् n.) mit schlanker Taille, breiten Hüften, roten Lippen, schwarzen Augen, gebogenem Nabel, aufrechten Brüsten.</p><blockquote><p>तनुमध्यं पृथुश्रोणि<br> रक्तौष्ठमसितेक्षणम् ।<br> नतनाभि वपुः स्त्रीणां<br> कं न हन्त्युन्नतस्तनम् ॥</p></blockquote><p>B) Deklinieren Sie in allen Ihnen bekannten Kasus क्षत्रिया f.</p><p>क्षत्रिया<br> क्षात्रियाम्<br> क्षत्रियया<br> क्षत्रियायास्</p><p>क्षत्रियास्<br> क्षत्रियास्<br> क्षत्रियाभिस्<br> क्षत्रियानाम्</p><p>C) Geben Sie die Stammformen (Bedeutung, Präsensklasse, Modus, 3. sg. Präs. Indikativ, 3. sg. Passiv, PPP, Absolutiva, Infinitiv) zu folgenden Verben:</p><p>१. सह्</p><blockquote><table tabindex="0"><thead><tr><th>सह् 1Ā ertragen</th><th>सहते</th></tr></thead><tbody><tr><td>Passiv</td><td>सह्यते</td></tr><tr><td>PPP</td><td>सोढ</td></tr><tr><td>Absolutiv 1</td><td>सोढ्वा</td></tr><tr><td>सहित्वा</td><td></td></tr><tr><td>Absolutiv 2</td><td>-सह्य</td></tr><tr><td>Infinitiv</td><td>सोढुम्</td></tr><tr><td>सहितुम्</td><td></td></tr></tbody></table></blockquote><p>२. पा (2x)</p><blockquote><table tabindex="0"><thead><tr><th>पा 1P trinken</th><th>पिबति</th></tr></thead><tbody><tr><td>Passiv</td><td>पीयते</td></tr><tr><td>PPP</td><td>पीत</td></tr><tr><td>Absolutiv 1</td><td>पीत्वा</td></tr><tr><td>Absolutiv 2</td><td>-पाय</td></tr><tr><td>Infinitiv</td><td>पातुम्</td></tr></tbody></table></blockquote><blockquote><table tabindex="0"><thead><tr><th>पा 2P hüten</th><th>पाति</th></tr></thead><tbody><tr><td>Passiv</td><td>पायते</td></tr><tr><td>PPP</td><td>पात</td></tr><tr><td>Absolutiv 1</td><td>पात्वा</td></tr><tr><td>Absolutiv 2</td><td>-पाय</td></tr><tr><td>Infinitiv</td><td>पातुम्</td></tr></tbody></table></blockquote><p>३. वच्</p><blockquote><table tabindex="0"><thead><tr><th>वच् 2P sprechen</th><th>वक्ति</th></tr></thead><tbody><tr><td>Passiv</td><td>उच्यते</td></tr><tr><td>PPP</td><td>उक्त</td></tr><tr><td>Absolutiv 1</td><td>उक्त्वा</td></tr><tr><td>Absolutiv 2</td><td>-उच्य</td></tr><tr><td>Infinitiv</td><td>वक्तुम्</td></tr></tbody></table></blockquote><p>४. हन्</p><blockquote><table tabindex="0"><thead><tr><th>हन् 2P erschlagen</th><th>हन्ति, घन्ति</th></tr></thead><tbody><tr><td>Passiv</td><td>हन्यते</td></tr><tr><td>PPP</td><td>हत</td></tr><tr><td>Absolutiv 1</td><td>हत्वा</td></tr><tr><td>Absolutiv 2</td><td>-हत्य</td></tr><tr><td>Infinitiv</td><td>हन्तुम्</td></tr></tbody></table></blockquote><p><img src="'+d+'" alt=""><br> Abb.: बालाः पिबन्ति<br> Hampi = ಹಂಪೆ<br> [Bildquelle: fraboof. -- <a href="http://www.flickr.com/photos/fraboof/2126653290/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/fraboof/2126653290/</a>. -- Zugriff am 2008-12-24. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, share alike)]</p>',63)])])}const m=t(s,[["render",o]]);export{g as __pageData,m as default};
